  ('evt_006', '2026-04-23T20:05:00.000Z', 'Tesla falls 3.4% despite earnings beat — capex guidance, not oil, is the driver', 'earnings', 30.2226, -97.618, 'Austin, TX (Tesla HQ)', 'Company report', '', '2026-04-23T20:05:00.000Z', null, '{evt_003}', 'direct', 3.5586199575237787),
